package sequence

import (
	"database/sql"
	"strings"
	"testing"
	"time"

	"github.com/usenurge/nurgesh/internal/db"
	_ "modernc.org/sqlite"
)

func setupTestDB(t *testing.T) *sql.DB {
	t.Helper()
	d, err := sql.Open("sqlite", ":memory:")
	if err != nil {
		t.Fatal(err)
	}
	if _, err := d.Exec(db.Schema); err != nil {
		t.Fatal(err)
	}
	return d
}

func TestMailboxFirstTouchCap(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	mailbox, err := EnsureMailbox(d, "sales@example.com", "gmail")
	if err != nil {
		t.Fatal(err)
	}

	now := time.Date(2026, 3, 24, 10, 0, 0, 0, time.UTC)
	for i := 0; i < mailbox.FirstTouchDailyCap; i++ {
		if err := CanSend(d, mailbox.ID, SendTypeFirstTouch, now); err != nil {
			t.Fatalf("unexpected cap error before limit: %v", err)
		}
		if err := RecordSend(d, mailbox.ID, SendTypeFirstTouch, now); err != nil {
			t.Fatal(err)
		}
	}

	if err := CanSend(d, mailbox.ID, SendTypeFirstTouch, now); err == nil {
		t.Fatal("expected first-touch cap error")
	}
}

func TestCreateEnrollmentAfterFirstTouch(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	mailbox, err := EnsureMailbox(d, "sales@example.com", "gmail")
	if err != nil {
		t.Fatal(err)
	}

	sentAt := time.Date(2026, 3, 24, 10, 0, 0, 0, time.UTC)
	enrollment, nextTask, err := CreateEnrollmentAfterFirstTouch(d, EnrollmentOptions{
		SequenceName: DefaultTemplateName,
		MailboxID:    mailbox.ID,
		ContactEmail: "jane@target.com",
		ContactName:  "Jane",
		Subject:      "Idea for TargetCo",
		ThreadID:     "thread-1",
		MessageID:    "msg-1",
		SentAt:       sentAt,
	})
	if err != nil {
		t.Fatal(err)
	}

	if enrollment.CurrentStep != 1 {
		t.Fatalf("current step = %d, want 1", enrollment.CurrentStep)
	}
	if nextTask == nil {
		t.Fatal("expected next task")
	}
	if nextTask.StepNumber != 2 {
		t.Fatalf("step number = %d, want 2", nextTask.StepNumber)
	}
	if nextTask.DueAt != sentAt.Add(72*time.Hour).Format(time.RFC3339) {
		t.Fatalf("due_at = %s, want %s", nextTask.DueAt, sentAt.Add(72*time.Hour).Format(time.RFC3339))
	}
}

func TestCreateEnrollmentAfterFirstTouchRejectsDuplicate(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	mailbox, err := EnsureMailbox(d, "sales@example.com", "gmail")
	if err != nil {
		t.Fatal(err)
	}

	sentAt := time.Date(2026, 3, 24, 10, 0, 0, 0, time.UTC)
	_, _, err = CreateEnrollmentAfterFirstTouch(d, EnrollmentOptions{
		SequenceName: DefaultTemplateName,
		MailboxID:    mailbox.ID,
		ContactEmail: "jane@target.com",
		Subject:      "Idea for TargetCo",
		SentAt:       sentAt,
	})
	if err != nil {
		t.Fatal(err)
	}

	_, _, err = CreateEnrollmentAfterFirstTouch(d, EnrollmentOptions{
		SequenceName: DefaultTemplateName,
		MailboxID:    mailbox.ID,
		ContactEmail: "jane@target.com",
		Subject:      "Idea for TargetCo",
		SentAt:       sentAt.Add(1 * time.Hour),
	})
	if err == nil {
		t.Fatal("expected duplicate enrollment error")
	}
}

func TestAdvanceTaskAfterSendCreatesNextTask(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	mailbox, err := EnsureMailbox(d, "sales@example.com", "gmail")
	if err != nil {
		t.Fatal(err)
	}

	sentAt := time.Date(2026, 3, 24, 10, 0, 0, 0, time.UTC)
	_, firstTask, err := CreateEnrollmentAfterFirstTouch(d, EnrollmentOptions{
		SequenceName: DefaultTemplateName,
		MailboxID:    mailbox.ID,
		ContactEmail: "jane@target.com",
		Subject:      "Idea for TargetCo",
		ThreadID:     "thread-1",
		MessageID:    "msg-1",
		SentAt:       sentAt,
	})
	if err != nil {
		t.Fatal(err)
	}

	nextTask, err := AdvanceTaskAfterSend(d, AdvanceOptions{
		TaskID:    firstTask.ID,
		ThreadID:  "thread-1",
		MessageID: "msg-2",
		SentAt:    sentAt.Add(72 * time.Hour),
	})
	if err != nil {
		t.Fatal(err)
	}

	if nextTask == nil {
		t.Fatal("expected next task")
	}
	if nextTask.StepNumber != 3 {
		t.Fatalf("step number = %d, want 3", nextTask.StepNumber)
	}

	enrollment, err := EnrollmentByID(d, firstTask.EnrollmentID)
	if err != nil {
		t.Fatal(err)
	}
	if enrollment.CurrentStep != 2 {
		t.Fatalf("current step = %d, want 2", enrollment.CurrentStep)
	}
}

func TestPauseEnrollmentHidesTasks(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	mailbox, err := EnsureMailbox(d, "sales@example.com", "gmail")
	if err != nil {
		t.Fatal(err)
	}

	sentAt := time.Date(2026, 3, 24, 10, 0, 0, 0, time.UTC)
	enrollment, _, err := CreateEnrollmentAfterFirstTouch(d, EnrollmentOptions{
		SequenceName: DefaultTemplateName,
		MailboxID:    mailbox.ID,
		ContactEmail: "jane@target.com",
		Subject:      "Idea for TargetCo",
		SentAt:       sentAt,
	})
	if err != nil {
		t.Fatal(err)
	}

	if err := PauseEnrollment(d, enrollment.ID); err != nil {
		t.Fatal(err)
	}

	tasks, err := ListTasks(d, TaskListOptions{
		IncludeFuture: true,
		Now:           sentAt,
	})
	if err != nil {
		t.Fatal(err)
	}
	if len(tasks) != 0 {
		t.Fatalf("expected paused enrollment tasks to be hidden, got %d", len(tasks))
	}
}

func TestSnoozeTaskMovesDueDate(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	mailbox, err := EnsureMailbox(d, "sales@example.com", "gmail")
	if err != nil {
		t.Fatal(err)
	}

	sentAt := time.Date(2026, 3, 24, 10, 0, 0, 0, time.UTC)
	_, task, err := CreateEnrollmentAfterFirstTouch(d, EnrollmentOptions{
		SequenceName: DefaultTemplateName,
		MailboxID:    mailbox.ID,
		ContactEmail: "jane@target.com",
		Subject:      "Idea for TargetCo",
		SentAt:       sentAt,
	})
	if err != nil {
		t.Fatal(err)
	}

	updated, err := SnoozeTask(d, task.ID, 2)
	if err != nil {
		t.Fatal(err)
	}

	want := sentAt.AddDate(0, 0, 5).Format(time.RFC3339)
	if updated.DueAt != want {
		t.Fatalf("due_at = %s, want %s", updated.DueAt, want)
	}

	enrollment, err := EnrollmentByID(d, task.EnrollmentID)
	if err != nil {
		t.Fatal(err)
	}
	if enrollment.NextDueAt != want {
		t.Fatalf("next_due_at = %s, want %s", enrollment.NextDueAt, want)
	}
}

func TestMinuteTemplateBecomesDueAfterOneMinute(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	mailbox, err := EnsureMailbox(d, "sales@example.com", "gmail")
	if err != nil {
		t.Fatal(err)
	}

	sentAt := time.Date(2026, 3, 24, 10, 0, 0, 0, time.UTC)
	_, task, err := CreateEnrollmentAfterFirstTouch(d, EnrollmentOptions{
		SequenceName: "test-3-touch-1m",
		MailboxID:    mailbox.ID,
		ContactEmail: "jane@target.com",
		Subject:      "Minute Test",
		SentAt:       sentAt,
	})
	if err != nil {
		t.Fatal(err)
	}
	if task == nil {
		t.Fatal("expected next task")
	}
	if task.DueAt != sentAt.Add(time.Minute).Format(time.RFC3339) {
