127→// shouldSkipAuth walks the command tree to check if any command in the
128→// chain has the skipAuth annotation. This handles cases like
129→// "nurge account login" where account has skipAuth.
130→func shouldSkipAuth(cmd *cobra.Command) bool {
131→	for c := cmd; c != nil; c = c.Parent() {
132→		if c.Annotations != nil && c.Annotations["skipAuth"] == "true" {
133→			return true
134→		}
135→	}
136→	return false
137→}
138→
139→func init() {
140→	rootCmd.AddCommand(versionCmd)
141→
142→	rootCmd.Flags().BoolVar(&initForce, "force", false, "Re-run all steps even if already completed")
143→	rootCmd.Flags().BoolVar(&initSkipHooks, "skip-hooks", false, "Skip Claude Code hook installation")
144→	rootCmd.Flags().BoolVar(&initVerbose, "verbose", false, "Show detailed output")
145→
146→	rootCmd.PersistentPreRunE = func(cmd *cobra.Command, args []string) error {
147→		// Root command (init) skips auth — it's the first thing a user runs
148→		if cmd == rootCmd ||
149→			shouldSkipAuth(cmd) ||
150→			cmd.Name() == "help" ||
151→			cmd.Name() == "completion" {
152→			return nil
153→		}
154→		_, err := account.EnsureAuth(GetConvexURL(), GetDashboardURL())
155→		return err
156→	}
157→}
158→
159→// isKnownCommand checks if name matches any registered subcommand.
160→func isKnownCommand(name string) bool {
161→	for _, c := range rootCmd.Commands() {
162→		if c.Name() == name {
163→			return true
164→		}
165→		for _, alias := range c.Aliases {
166→			if alias == name {
167→				return true
168→			}
169→		}
170→	}
171→	return name == "help" || name == "completion"
172→}
173→
174→func Execute() error {
175→	// Allow "nurge my-outbound" as shorthand for "nurge init my-outbound".
176→	// Cobra rejects unknown subcommands before RunE runs, so we rewrite args
177→	// when the first arg isn't a known subcommand or flag.
178→	if len(os.Args) > 1 {
179→		first := os.Args[1]
180→		if !strings.HasPrefix(first, "-") && !isKnownCommand(first) {
181→			os.Args = append([]string{os.Args[0], "init"}, os.Args[1:]...)
182→		}
183→	}
184→	return rootCmd.Execute()
185→}
