  2→
  3→import (
  4→	"encoding/json"
  5→	"fmt"
  6→	"strings"
  7→	"time"
  8→
  9→	"github.com/spf13/cobra"
 10→	"github.com/usenurge/nurgesh/internal/db"
 11→	"github.com/usenurge/nurgesh/internal/email"
 12→	"github.com/usenurge/nurgesh/internal/project"
 13→	"github.com/usenurge/nurgesh/internal/sequence"
 14→)
 15→
 16→var (
 17→	sendTo          string
 18→	sendCc          string
 19→	sendSubject     string
 20→	sendBody        string
 21→	sendSequence    string
 22→	sendCampaign    string
 23→	sendTaskID      string
 24→	sendSendType    string
 25→	sendContactName string
 26→)
 27→
 28→var sendCmd = &cobra.Command{
 29→	Use:   "send",
 30→	Short: "Send an email via Gmail",
 31→	Long:  "Send an email through your connected Gmail account.",
 32→	RunE: func(cmd *cobra.Command, args []string) error {
 33→		if sendSequence != "" && sendTaskID != "" {
 34→			return fmt.Errorf("--sequence and --task-id cannot be used together")
 35→		}
 36→
 37→		// Get sender address from config
 38→		cfg, err := project.Load()
 39→		if err != nil {
 40→			return fmt.Errorf("loading config: %w", err)
 41→		}
 42→
 43→		gmail, ok := cfg.Connectors["gmail"]
 44→		if !ok || !gmail.Connected {
 45→			return fmt.Errorf("Gmail not connected. Run: nurge connect gmail")
 46→		}
 47→
 48→		d, err := db.Open()
 49→		if err != nil {
 50→			return fmt.Errorf("opening database: %w", err)
 51→		}
 52→		defer d.Close()
 53→
 54→		mailbox, err := sequence.EnsureMailbox(d, gmail.Account, "gmail")
 55→		if err != nil {
 56→			return fmt.Errorf("ensuring mailbox state: %w", err)
 57→		}
 58→
 59→		effectiveSendType := sequence.NormalizeSendType(sendSendType)
 60→		var task *sequence.Task
 61→		selectedMailbox := mailbox
 62→		if sendSequence != "" {
 63→			effectiveSendType = sequence.SendTypeFirstTouch
 64→		}
 65→		if sendTaskID != "" {
 66→			task, err = sequence.TaskByID(d, sendTaskID)
 67→			if err != nil {
 68→				return err
 69→			}
 70→			effectiveSendType = task.SendType
 71→			selectedMailbox, err = sequence.ResolveTaskMailbox(d, *task, gmail.Account, timeNow())
 72→			if err != nil {
 73→				return err
 74→			}
 75→			if sendTo == "" {
 76→				sendTo = task.ContactEmail
 77→			} else if !strings.EqualFold(strings.TrimSpace(sendTo), strings.TrimSpace(task.ContactEmail)) {
 78→				return fmt.Errorf("--task-id %s belongs to %s, but --to was %s", task.ID, task.ContactEmail, sendTo)
 79→			}
 80→			if sendSubject == "" || sendBody == "" {
 81→				renderedSubject, renderedBody, err := sequence.RenderTaskContent(d, *task)
 82→				if err != nil {
 83→					return err
 84→				}
 85→				if sendSubject == "" {
 86→					sendSubject = renderedSubject
 87→				}
 88→				if sendBody == "" {
 89→					sendBody = renderedBody
 90→				}
 91→			}
 92→		}
 93→
 94→		sentAt := timeNow()
 95→		if sendTo == "" {
 96→			return fmt.Errorf("recipient (--to) is required")
 97→		}
 98→		if sendSubject == "" {
 99→			return fmt.Errorf("subject (--subject) is required")
100→		}
101→		if sendBody == "" {
102→			return fmt.Errorf("body (--body) is required")
103→		}
104→		if sendSequence != "" {
105→			enrollment, err := sequence.ActiveEnrollmentForContact(d, selectedMailbox.ID, sendTo)
106→			if err != nil {
107→				return err
108→			}
109→			if enrollment != nil {
110→				return fmt.Errorf("%s already has an active sequence enrollment (%s)", sendTo, enrollment.ID)
111→			}
112→		}
113→		if suppression, suppressed, err := sequence.IsSuppressed(d, sendTo); err != nil {
114→			return err
115→		} else if suppressed {
116→			return fmt.Errorf("%s %s is suppressed (%s)", suppression.Scope, suppression.Value, suppression.Reason)
117→		}
118→
119→		if err := sequence.CanSend(d, selectedMailbox.ID, effectiveSendType, sentAt); err != nil {
120→			return err
121→		}
122→
123→		srv, err := email.NewClient("")
124→		if err != nil {
125→			return fmt.Errorf("connecting to Gmail: %w", err)
126→		}
127→		fromAddress := strings.TrimSpace(selectedMailbox.TransportEmail)
128→		if fromAddress == "" {
129→			fromAddress = strings.TrimSpace(selectedMailbox.Email)
130→		}
131→
132→		sent, err := email.Send(srv, fromAddress, email.SendOptions{
133→			To:       sendTo,
134→			Cc:       sendCc,
135→			Subject:  sendSubject,
136→			Body:     sendBody,
137→			ThreadID: chooseSendThreadID(task),
138→		})
139→		if err != nil {
140→			return err
141→		}
142→
143→		if err := sequence.RecordSend(d, selectedMailbox.ID, effectiveSendType, sentAt); err != nil {
144→			return fmt.Errorf("email sent (message ID: %s) but failed to record mailbox usage: %w", sent.MessageID, err)
145→		}
146→		if err := email.StoreEmail(d, &email.RawMessage{
147→			ID:        sent.MessageID,
148→			Source:    "gmail",
149→			Direction: "outbound",
150→			ThreadID:  sent.ThreadID,
151→			Subject:   sendSubject,
152→			FromEmail: fromAddress,
153→			ToEmails:  recipientsJSON(sendTo),
154→			CcEmails:  recipientsJSON(sendCc),
155→			Date:      sentAt.UTC().Format(time.RFC3339),
156→			Labels:    `["SENT"]`,
157→		}); err != nil {
158→			return fmt.Errorf("email sent (message ID: %s) but failed to store local send state: %w", sent.MessageID, err)
159→		}
160→
161→		fmt.Printf("  ✓ Sent to %s (message ID: %s)\n", sendTo, sent.MessageID)
162→
163→		if sendSequence != "" {
164→			enrollment, nextTask, err := sequence.CreateEnrollmentAfterFirstTouch(d, sequence.EnrollmentOptions{
165→				SequenceName: sendSequence,
166→				CampaignName: sendCampaign,
167→				MailboxID:    selectedMailbox.ID,
168→				ContactEmail: sendTo,
169→				ContactName:  sendContactName,
170→				Subject:      sendSubject,
171→				InitialBody:  sendBody,
172→				ThreadID:     sent.ThreadID,
173→				MessageID:    sent.MessageID,
174→				SentAt:       sentAt,
175→			})
176→			if err != nil {
177→				return fmt.Errorf("email sent (message ID: %s) but failed to create sequence state: %w", sent.MessageID, err)
178→			}
179→
180→			fmt.Printf("  ↳ Enrolled in sequence %s (%s)\n", enrollment.SequenceName, enrollment.ID)
181→			if nextTask != nil {
182→				fmt.Printf("  ↳ Next follow-up task: %s due %s\n", nextTask.ID, shortDate(nextTask.DueAt))
183→			}
184→		}
185→
186→		if task != nil {
187→			nextTask, err := sequence.AdvanceTaskAfterSend(d, sequence.AdvanceOptions{
188→				TaskID:    task.ID,
189→				ThreadID:  sent.ThreadID,
190→				MessageID: sent.MessageID,
191→				MailboxID: selectedMailbox.ID,
192→				SentAt:    sentAt,
193→			})
194→			if err != nil {
195→				return fmt.Errorf("email sent (message ID: %s) but failed to advance task %s: %w", sent.MessageID, task.ID, err)
196→			}
197→			if nextTask != nil {
198→				fmt.Printf("  ↳ Next follow-up task: %s due %s\n", nextTask.ID, shortDate(nextTask.DueAt))
199→			} else {
200→				fmt.Println("  ↳ Sequence completed")
201→			}
202→		}
