252→func preview(body string, limit int) string {
253→	body = strings.TrimSpace(body)
254→	body = strings.ReplaceAll(body, "\n", " ")
255→	if limit <= 0 || len(body) <= limit {
256→		return body
257→	}
258→	return body[:limit-1] + "…"
259→}
260→
261→func dispatchSubject(item sequence.DispatchTask) string {
262→	if strings.TrimSpace(item.RenderedSubject) != "" {
263→		return strings.TrimSpace(item.RenderedSubject)
264→	}
265→	return strings.TrimSpace(item.Subject)
266→}
