118→// RevokeToken revokes a token on the Convex backend.
119→func (c *ConvexClient) RevokeToken(token string) error {
120→	body, _ := json.Marshal(map[string]string{"token": token})
121→	resp, err := c.httpClient.Post(
122→		c.baseURL+"/api/revoke-token",
123→		"application/json",
124→		bytes.NewReader(body),
125→	)
126→	if err != nil {
