477→	if err != nil {
478→		return err
479→	}
480→
481→	column := usageColumn(sendType)
482→	if column == "" {
483→		return nil
484→	}
485→
486→	if _, err := d.Exec(
487→		fmt.Sprintf(`UPDATE mailbox_daily_usage SET %s = %s + 1 WHERE mailbox_id = ? AND usage_day = ?`, column, column),
488→		mailboxID, dayKey(now),
489→	); err != nil {
490→		return err
491→	}
