564→			thread_id, last_message_id, status, status_reason, reply_state, current_step, total_steps, last_sent_at, last_reply_at, next_due_at, initial_body
565→		) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
566→		enrollmentID, template.Name, defaultCampaignName(opts), opts.MailboxID, opts.ContactEmail, opts.ContactName,
