225→func recipientsJSON(raw string) string {
226→	raw = strings.TrimSpace(raw)
227→	if raw == "" {
228→		return "[]"
229→	}
230→	parts := strings.Split(raw, ",")
231→	recipients := make([]string, 0, len(parts))
232→	for _, part := range parts {
233→		part = strings.TrimSpace(part)
234→		if part != "" {
235→			recipients = append(recipients, part)
236→		}
237→	}
238→	data, _ := json.Marshal(recipients)
239→	return string(data)
240→}
