	Rows        []SyncRow `json:"rows"`
	SyncVersion int64     `json:"sync_version"`
}

// PushResponse contains server-assigned versions for pushed rows.
type PushResponse struct {
	Versions map[string]int64 `json:"versions"` // id → sync_version
}

// SendIntentRequest is the payload for creating a send intent on Convex.
