	body, err := json.Marshal(map[string]any{
		"token":        token,
		"sync_version": lastSyncVersion,
	})
	if err != nil {
		return nil, fmt.Errorf("marshaling pull request: %w", err)
	}

	resp, err := c.httpClient.Post(
		c.baseURL+"/api/pull-execution-state",
		"application/json",
		bytes.NewReader(body),
	)
	if err != nil {
		return nil, fmt.Errorf("calling pull-execution-state: %w", err)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(resp.Body)
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	if resp.StatusCode != 200 {
		return nil, fmt.Errorf("pull-execution-state failed (status %d): %s", resp.StatusCode, string(data))
	}

	var result PullResponse
	if err := json.Unmarshal(data, &result); err != nil {
		return nil, fmt.Errorf("parsing pull response: %w", err)
	}
	return &result, nil
}

