// executionTables are tables where Convex is authoritative.
// Pull direction: Convex → SQLite.
var executionTables = []string{
	"emails",
	"mailboxes",
	"mailbox_send_events",
	"sequence_enrollments",
	"follow_up_tasks",
	"suppressions",
	"reply_events",
	"sequence_drafts",
}

// localTables are tables where SQLite is authoritative.
// Push direction: SQLite → Convex.
var localTables = []string{
	"contacts",
	"learnings",
	"skill_versions",
	"deals",
}

const batchSize = 500

// SyncState tracks the last sync position per direction.
type SyncState struct {
	LastPullVersion int64  `json:"last_pull_version"`
	LastPushAt      string `json:"last_push_at"`
}

// Engine handles bidirectional sync between SQLite and Convex.
type Engine struct {
	db     *sql.DB
	client *account.ConvexClient
	token  string
}

// NewEngine creates a sync engine.
func NewEngine(db *sql.DB, client *account.ConvexClient, token string) *Engine {
	return &Engine{db: db, client: client, token: token}
}

// PullResult contains stats from a pull operation.
type PullResult struct {
	TablesUpdated int
	RowsUpserted  int
}

// PushResult contains stats from a push operation.
type PushResult struct {
	TablesScanned int
	RowsPushed    int
}

// SyncResult contains stats from a full sync (pull + push).
type SyncResult struct {
	Pull PullResult
	Push PushResult
}

// Sync performs a full sync: pull execution state, then push local state.
func (e *Engine) Sync() (*SyncResult, error) {
	pullResult, err := e.Pull()
	if err != nil {
		return nil, fmt.Errorf("pull failed: %w", err)
	}

	pushResult, err := e.Push()
	if err != nil {
		return nil, fmt.Errorf("push failed: %w", err)
	}

	return &SyncResult{Pull: *pullResult, Push: *pushResult}, nil
}

// Pull fetches execution state from Convex and upserts into SQLite.
func (e *Engine) Pull() (*PullResult, error) {
	state, err := e.loadSyncState()
	if err != nil {
		return nil, fmt.Errorf("loading sync state: %w", err)
	}

	resp, err := e.client.PullExecutionState(e.token, state.LastPullVersion)
	if err != nil {
		return nil, fmt.Errorf("pulling from Convex: %w", err)
	}

	result := &PullResult{}
	tablesUpdated := map[string]bool{}

	for _, row := range resp.Rows {
		if err := e.upsertRow(row); err != nil {
			return nil, fmt.Errorf("upserting %s/%s: %w", row.Table, row.ID, err)
		}
		result.RowsUpserted++
		tablesUpdated[row.Table] = true
	}
	result.TablesUpdated = len(tablesUpdated)

	if resp.SyncVersion > state.LastPullVersion {
		state.LastPullVersion = resp.SyncVersion
		if err := e.saveSyncState(state); err != nil {
			return nil, fmt.Errorf("saving sync state: %w", err)
		}
	}

	return result, nil
}

// Push sends local state changes to Convex.
func (e *Engine) Push() (*PushResult, error) {
	state, err := e.loadSyncState()
	if err != nil {
		return nil, fmt.Errorf("loading sync state: %w", err)
	}

	result := &PushResult{}
	var allRows []account.SyncRow

	for _, table := range localTables {
		rows, err := e.changedLocalRows(table, state.LastPushAt)
		if err != nil {
			return nil, fmt.Errorf("reading changed rows from %s: %w", table, err)
		}
		allRows = append(allRows, rows...)
		result.TablesScanned++
	}

	// Also push email classifications (local authority for the classification field)
	classRows, err := e.changedEmailClassifications(state.LastPushAt)
	if err != nil {
		return nil, fmt.Errorf("reading changed email classifications: %w", err)
	}
	allRows = append(allRows, classRows...)

	if len(allRows) == 0 {
		return result, nil
	}

	// Push in batches
	for i := 0; i < len(allRows); i += batchSize {
		end := i + batchSize
		if end > len(allRows) {
			end = len(allRows)
		}
		batch := allRows[i:end]

		resp, err := e.client.PushLocalState(e.token, batch)
		if err != nil {
			return nil, fmt.Errorf("pushing batch %d-%d: %w", i, end, err)
		}

		// Update local sync_version from server response
		for id, version := range resp.Versions {
			for _, row := range batch {
				if row.ID == id {
					if err := e.updateSyncVersion(row.Table, id, version); err != nil {
						return nil, fmt.Errorf("updating sync_version for %s/%s: %w", row.Table, id, err)
					}
					break
				}
			}
		}
		result.RowsPushed += len(batch)
	}

	state.LastPushAt = time.Now().UTC().Format(time.RFC3339)
	if err := e.saveSyncState(state); err != nil {
		return nil, fmt.Errorf("saving sync state: %w", err)
	}

	return result, nil
}

// upsertRow writes a Convex row into the local SQLite table.
func (e *Engine) upsertRow(row account.SyncRow) error {
	if len(row.Data) == 0 {
		return nil
	}

	columns := []string{"id"}
	placeholders := []string{"?"}
	values := []any{row.ID}
	updateParts := []string{}

	for col, val := range row.Data {
		columns = append(columns, col)
		placeholders = append(placeholders, "?")
		values = append(values, val)
		updateParts = append(updateParts, fmt.Sprintf("%s = excluded.%s", col, col))
	}

	// Always set sync_version
	columns = append(columns, "sync_version")
	placeholders = append(placeholders, "?")
	values = append(values, row.Version)
	updateParts = append(updateParts, "sync_version = excluded.sync_version")

	query := fmt.Sprintf(
		"INSERT INTO %s (%s) VALUES (%s) ON CONFLICT(id) DO UPDATE SET %s",
		row.Table,
		joinStrings(columns, ", "),
		joinStrings(placeholders, ", "),
		joinStrings(updateParts, ", "),
	)

	_, err := e.db.Exec(query, values...)
	return err
}

// changedLocalRows returns rows from a local-state table changed since lastPushAt.
func (e *Engine) changedLocalRows(table, lastPushAt string) ([]account.SyncRow, error) {
	var rows []account.SyncRow

	query := fmt.Sprintf("SELECT * FROM %s", table)
	args := []any{}
	if lastPushAt != "" {
		query += " WHERE updated_at > ?"
		args = append(args, lastPushAt)
	}

	sqlRows, err := e.db.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer sqlRows.Close()

	cols, err := sqlRows.Columns()
	if err != nil {
		return nil, err
	}

	for sqlRows.Next() {
		values := make([]any, len(cols))
		ptrs := make([]any, len(cols))
		for i := range values {
			ptrs[i] = &values[i]
		}
		if err := sqlRows.Scan(ptrs...); err != nil {
			return nil, err
		}

		data := map[string]any{}
		var id string
		for i, col := range cols {
			if col == "id" {
				id = fmt.Sprintf("%v", values[i])
			}
			if col == "sync_version" {
				continue // don't push sync_version back
			}
			data[col] = values[i]
		}

		rows = append(rows, account.SyncRow{
			Table: table,
			ID:    id,
			Data:  data,
		})
	}

	return rows, sqlRows.Err()
}

// changedEmailClassifications returns emails with updated classifications.
func (e *Engine) changedEmailClassifications(lastPushAt string) ([]account.SyncRow, error) {
	query := `SELECT id, class, class_confidence, classified_by FROM emails WHERE class != 'unclassified'`
	args := []any{}
	if lastPushAt != "" {
		// Emails don't have updated_at, so push all classified emails on each push.
		// This is idempotent — Convex will ignore unchanged classifications.
	}

	sqlRows, err := e.db.Query(query, args...)
	if err != nil {
		return nil, err
	}
	defer sqlRows.Close()

	var rows []account.SyncRow
	for sqlRows.Next() {
		var id, class, classifiedBy string
		var confidence float64
		if err := sqlRows.Scan(&id, &class, &confidence, &classifiedBy); err != nil {
			return nil, err
		}

		rows = append(rows, account.SyncRow{
			Table: "emails",
			ID:    id,
			Data: map[string]any{
				"class":            class,
				"class_confidence": confidence,
				"classified_by":    classifiedBy,
			},
		})
	}

	return rows, sqlRows.Err()
}

// updateSyncVersion sets the sync_version for a specific row.
func (e *Engine) updateSyncVersion(table, id string, version int64) error {
	query := fmt.Sprintf("UPDATE %s SET sync_version = ? WHERE id = ?", table)
	_, err := e.db.Exec(query, version, id)
	return err
}

const syncStateKey = "_sync_state"

// loadSyncState reads the sync cursor from a local config-like store.
func (e *Engine) loadSyncState() (*SyncState, error) {
	// Store sync state in a simple key-value row in connectors table (reusing existing table)
	var data string
	err := e.db.QueryRow(
		`SELECT sync_cursor FROM connectors WHERE id = ?`, syncStateKey,
	).Scan(&data)
	if err == sql.ErrNoRows {
		return &SyncState{}, nil
	}
	if err != nil {
		return nil, err
	}

	var state SyncState
	if err := json.Unmarshal([]byte(data), &state); err != nil {
		return &SyncState{}, nil
	}
	return &state, nil
}

// saveSyncState persists the sync cursor.
func (e *Engine) saveSyncState(state *SyncState) error {
	data, err := json.Marshal(state)
	if err != nil {
		return err
	}

	_, err = e.db.Exec(`
		INSERT INTO connectors (id, type, sync_cursor)
		VALUES (?, 'sync', ?)
		ON CONFLICT(id) DO UPDATE SET sync_cursor = excluded.sync_cursor`,
		syncStateKey, string(data),
	)
	return err
}

func joinStrings(parts []string, sep string) string {
	result := ""
	for i, p := range parts {
		if i > 0 {
			result += sep
		}
		result += p
	}
	return result
}

