package sync

import (
	"database/sql"
	"testing"

	"github.com/usenurge/nurgesh/internal/account"
	"github.com/usenurge/nurgesh/internal/db"
	_ "modernc.org/sqlite"
)

func setupTestDB(t *testing.T) *sql.DB {
	t.Helper()
	d, err := sql.Open("sqlite", ":memory:")
	if err != nil {
		t.Fatal(err)
	}
	if _, err := d.Exec(db.Schema); err != nil {
		t.Fatal(err)
	}
	return d
}

func TestNewTablesExist(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	// mailbox_send_events table should exist
	_, err := d.Exec(`INSERT INTO mailbox_send_events (id, mailbox_id, send_type, sent_at) VALUES ('mse-1', 'mbx-1', 'first_touch', '2026-03-24T10:00:00Z')`)
	if err != nil {
		t.Fatalf("mailbox_send_events table not created: %v", err)
	}

	// sequence_drafts table should exist
	_, err = d.Exec(`INSERT INTO sequence_drafts (id, enrollment_id, task_id, step_number) VALUES ('sd-1', 'enr-1', 'task-1', 2)`)
	if err != nil {
		t.Fatalf("sequence_drafts table not created: %v", err)
	}
}

func TestSequenceDraftsFields(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	_, err := d.Exec(`
		INSERT INTO sequence_drafts (id, enrollment_id, task_id, step_number, subject, body, channel, status, generated_by, generated_context)
		VALUES ('sd-1', 'enr-1', 'task-1', 2, 'Follow up', 'Hey, just checking in', 'email', 'pending', 'nurge-outbound-v3', '{"icp_hash":"abc123"}')
	`)
	if err != nil {
		t.Fatal(err)
	}

	var channel, status, generatedBy, generatedContext string
	err = d.QueryRow(`SELECT channel, status, generated_by, generated_context FROM sequence_drafts WHERE id = 'sd-1'`).
		Scan(&channel, &status, &generatedBy, &generatedContext)
	if err != nil {
		t.Fatal(err)
	}
	if channel != "email" || status != "pending" || generatedBy != "nurge-outbound-v3" {
		t.Fatalf("unexpected draft fields: channel=%s status=%s generated_by=%s", channel, status, generatedBy)
	}
}

func TestMailboxSendEventsDailyCapQuery(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	// Insert a mailbox
	_, err := d.Exec(`INSERT INTO mailboxes (id, email, provider) VALUES ('mbx-1', 'sales@example.com', 'gmail')`)
	if err != nil {
		t.Fatal(err)
	}

	// Insert send events
	for i := 0; i < 5; i++ {
		_, err := d.Exec(`INSERT INTO mailbox_send_events (id, mailbox_id, send_type, sent_at) VALUES (?, 'mbx-1', 'first_touch', '2026-03-24T10:00:00Z')`,
			"mse-"+string(rune('a'+i)))
		if err != nil {
			t.Fatal(err)
		}
	}
	// One follow-up on same day
	_, err = d.Exec(`INSERT INTO mailbox_send_events (id, mailbox_id, send_type, sent_at) VALUES ('mse-fu', 'mbx-1', 'follow_up', '2026-03-24T11:00:00Z')`)
	if err != nil {
		t.Fatal(err)
	}

	// Count first touches for the day
	var count int
	err = d.QueryRow(`SELECT COUNT(*) FROM mailbox_send_events WHERE mailbox_id = 'mbx-1' AND DATE(sent_at) = '2026-03-24' AND send_type = 'first_touch'`).Scan(&count)
	if err != nil {
		t.Fatal(err)
	}
	if count != 5 {
		t.Fatalf("first_touch count = %d, want 5", count)
	}

	// Count follow-ups
	err = d.QueryRow(`SELECT COUNT(*) FROM mailbox_send_events WHERE mailbox_id = 'mbx-1' AND DATE(sent_at) = '2026-03-24' AND send_type = 'follow_up'`).Scan(&count)
	if err != nil {
		t.Fatal(err)
	}
	if count != 1 {
		t.Fatalf("follow_up count = %d, want 1", count)
	}
}

func TestUnipileIDMigrationFields(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	// Test emails Unipile fields
	_, err := d.Exec(`INSERT INTO emails (id, source, thread_id, from_email, to_emails, date, unipile_id, provider_id, unipile_account_id) VALUES ('e-1', 'gmail', 't-1', 'me@example.com', '["them@example.com"]', '2026-03-24', 'uni-123', '{"messageId":"abc"}', 'acc-1')`)
	if err != nil {
		t.Fatalf("emails Unipile fields not added: %v", err)
	}

	var unipileID, providerID, unipileAccountID string
	err = d.QueryRow(`SELECT unipile_id, provider_id, unipile_account_id FROM emails WHERE id = 'e-1'`).Scan(&unipileID, &providerID, &unipileAccountID)
	if err != nil {
		t.Fatal(err)
	}
	if unipileID != "uni-123" || providerID != `{"messageId":"abc"}` || unipileAccountID != "acc-1" {
		t.Fatalf("unexpected Unipile ID fields: %s, %s, %s", unipileID, providerID, unipileAccountID)
	}
}

func TestFollowUpTaskSendStatus(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	_, err := d.Exec(`INSERT INTO mailboxes (id, email, provider) VALUES ('mbx-1', 'sales@example.com', 'gmail')`)
	if err != nil {
		t.Fatal(err)
	}
	_, err = d.Exec(`INSERT INTO sequence_enrollments (id, sequence_name, mailbox_id, contact_email) VALUES ('enr-1', 'default-3-touch', 'mbx-1', 'jane@target.com')`)
	if err != nil {
		t.Fatal(err)
	}

	// Insert task with send_status
	_, err = d.Exec(`INSERT INTO follow_up_tasks (id, enrollment_id, mailbox_id, contact_email, step_number, due_at, send_status, unipile_message_id, provider_id) VALUES ('task-1', 'enr-1', 'mbx-1', 'jane@target.com', 2, '2026-03-27T10:00:00Z', 'pending_remote_send', 'uni-msg-1', '{"messageId":"gmail-123"}')`)
	if err != nil {
		t.Fatalf("follow_up_tasks send_status field not added: %v", err)
	}

	var sendStatus, unipileMsgID, taskProviderID string
	err = d.QueryRow(`SELECT send_status, unipile_message_id, provider_id FROM follow_up_tasks WHERE id = 'task-1'`).Scan(&sendStatus, &unipileMsgID, &taskProviderID)
	if err != nil {
		t.Fatal(err)
	}
	if sendStatus != "pending_remote_send" {
		t.Fatalf("send_status = %s, want pending_remote_send", sendStatus)
	}
	if unipileMsgID != "uni-msg-1" {
		t.Fatalf("unipile_message_id = %s, want uni-msg-1", unipileMsgID)
	}
}

func TestEnrollmentUnipileFields(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	_, err := d.Exec(`INSERT INTO mailboxes (id, email, provider) VALUES ('mbx-1', 'sales@example.com', 'gmail')`)
	if err != nil {
		t.Fatal(err)
	}

	_, err = d.Exec(`INSERT INTO sequence_enrollments (id, sequence_name, mailbox_id, contact_email, unipile_thread_provider_id, unipile_account_id) VALUES ('enr-1', 'default-3-touch', 'mbx-1', 'jane@target.com', '{"threadId":"gmail-thread-1"}', 'acc-1')`)
	if err != nil {
		t.Fatalf("enrollment Unipile fields not added: %v", err)
	}

	var threadProviderID, enrollAccountID string
	err = d.QueryRow(`SELECT unipile_thread_provider_id, unipile_account_id FROM sequence_enrollments WHERE id = 'enr-1'`).Scan(&threadProviderID, &enrollAccountID)
	if err != nil {
		t.Fatal(err)
	}
	if threadProviderID != `{"threadId":"gmail-thread-1"}` || enrollAccountID != "acc-1" {
		t.Fatalf("unexpected enrollment Unipile fields: %s, %s", threadProviderID, enrollAccountID)
	}
}

func TestSyncVersionOnAllTables(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	tables := []struct {
		name      string
		insertSQL string
	}{
		{"emails", `INSERT INTO emails (id, source, thread_id, from_email, to_emails, date, sync_version) VALUES ('e-1', 'gmail', 't-1', 'me@example.com', '["them@example.com"]', '2026-03-24', 42)`},
		{"contacts", `INSERT INTO contacts (id, source, email, sync_version) VALUES ('c-1', 'gmail', 'them@example.com', 42)`},
		{"mailboxes", `INSERT INTO mailboxes (id, email, provider, sync_version) VALUES ('mbx-1', 'sales@example.com', 'gmail', 42)`},
		{"sequence_enrollments", `INSERT INTO sequence_enrollments (id, sequence_name, mailbox_id, contact_email, sync_version) VALUES ('enr-1', 'default-3-touch', 'mbx-1', 'jane@target.com', 42)`},
		{"follow_up_tasks", `INSERT INTO follow_up_tasks (id, enrollment_id, mailbox_id, contact_email, step_number, due_at, sync_version) VALUES ('task-1', 'enr-1', 'mbx-1', 'jane@target.com', 2, '2026-03-27T10:00:00Z', 42)`},
		{"suppressions", `INSERT INTO suppressions (id, scope, value, sync_version) VALUES ('sup-1', 'email', 'blocked@example.com', 42)`},
		{"reply_events", `INSERT INTO reply_events (id, enrollment_id, mailbox_id, thread_id, message_id, contact_email, occurred_at, sync_version) VALUES ('re-1', 'enr-1', 'mbx-1', 't-1', 'msg-1', 'jane@target.com', '2026-03-24T12:00:00Z', 42)`},
		{"learnings", `INSERT INTO learnings (id, type, content, sync_version) VALUES (1, 'tone', 'be more casual', 42)`},
		{"deals", `INSERT INTO deals (id, source, source_id, name, sync_version) VALUES ('d-1', 'hubspot', 'h-1', 'Big Deal', 42)`},
	}

	for _, tc := range tables {
		_, err := d.Exec(tc.insertSQL)
		if err != nil {
			t.Fatalf("table %s: sync_version column missing or insert failed: %v", tc.name, err)
		}

		var sv int
		err = d.QueryRow("SELECT sync_version FROM "+tc.name+" LIMIT 1").Scan(&sv)
		if err != nil {
			t.Fatalf("table %s: reading sync_version failed: %v", tc.name, err)
		}
		if sv != 42 {
			t.Fatalf("table %s: sync_version = %d, want 42", tc.name, sv)
		}
	}
}

func TestUpsertRow(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	engine := NewEngine(d, nil, "")

	// Insert a new row via upsertRow
