func TestFollowUpTaskSendStatus(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	_, err := d.Exec(`INSERT INTO mailboxes (id, email, provider) VALUES ('mbx-1', 'sales@example.com', 'gmail')`)
	if err != nil {
		t.Fatal(err)
	}
	_, err = d.Exec(`INSERT INTO sequence_enrollments (id, sequence_name, mailbox_id, contact_email) VALUES ('enr-1', 'default-3-touch', 'mbx-1', 'jane@target.com')`)
	if err != nil {
		t.Fatal(err)
	}

	// Insert task with send_status
	_, err = d.Exec(`INSERT INTO follow_up_tasks (id, enrollment_id, mailbox_id, contact_email, step_number, due_at, send_status, unipile_message_id, provider_id) VALUES ('task-1', 'enr-1', 'mbx-1', 'jane@target.com', 2, '2026-03-27T10:00:00Z', 'pending_remote_send', 'uni-msg-1', '{"messageId":"gmail-123"}')`)
	if err != nil {
		t.Fatalf("follow_up_tasks send_status field not added: %v", err)
	}

	var sendStatus, unipileMsgID, taskProviderID string
	err = d.QueryRow(`SELECT send_status, unipile_message_id, provider_id FROM follow_up_tasks WHERE id = 'task-1'`).Scan(&sendStatus, &unipileMsgID, &taskProviderID)
	if err != nil {
		t.Fatal(err)
	}
	if sendStatus != "pending_remote_send" {
		t.Fatalf("send_status = %s, want pending_remote_send", sendStatus)
