func TestEnrollmentUnipileFields(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	_, err := d.Exec(`INSERT INTO mailboxes (id, email, provider) VALUES ('mbx-1', 'sales@example.com', 'gmail')`)
	if err != nil {
		t.Fatal(err)
	}

	_, err = d.Exec(`INSERT INTO sequence_enrollments (id, sequence_name, mailbox_id, contact_email, unipile_thread_provider_id, unipile_account_id) VALUES ('enr-1', 'default-3-touch', 'mbx-1', 'jane@target.com', '{"threadId":"gmail-thread-1"}', 'acc-1')`)
	if err != nil {
		t.Fatalf("enrollment Unipile fields not added: %v", err)
	}

	var threadProviderID, enrollAccountID string
	err = d.QueryRow(`SELECT unipile_thread_provider_id, unipile_account_id FROM sequence_enrollments WHERE id = 'enr-1'`).Scan(&threadProviderID, &enrollAccountID)
	if err != nil {
		t.Fatal(err)
	}
	if threadProviderID != `{"threadId":"gmail-thread-1"}` || enrollAccountID != "acc-1" {
		t.Fatalf("unexpected enrollment Unipile fields: %s, %s", threadProviderID, enrollAccountID)
	}
}

func TestSyncVersionOnAllTables(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	tables := []struct {
		name      string
		insertSQL string
	}{
		{"emails", `INSERT INTO emails (id, source, thread_id, from_email, to_emails, date, sync_version) VALUES ('e-1', 'gmail', 't-1', 'me@example.com', '["them@example.com"]', '2026-03-24', 42)`},
		{"contacts", `INSERT INTO contacts (id, source, email, sync_version) VALUES ('c-1', 'gmail', 'them@example.com', 42)`},
		{"mailboxes", `INSERT INTO mailboxes (id, email, provider, sync_version) VALUES ('mbx-1', 'sales@example.com', 'gmail', 42)`},
		{"sequence_enrollments", `INSERT INTO sequence_enrollments (id, sequence_name, mailbox_id, contact_email, sync_version) VALUES ('enr-1', 'default-3-touch', 'mbx-1', 'jane@target.com', 42)`},
		{"follow_up_tasks", `INSERT INTO follow_up_tasks (id, enrollment_id, mailbox_id, contact_email, step_number, due_at, sync_version) VALUES ('task-1', 'enr-1', 'mbx-1', 'jane@target.com', 2, '2026-03-27T10:00:00Z', 42)`},
		{"suppressions", `INSERT INTO suppressions (id, scope, value, sync_version) VALUES ('sup-1', 'email', 'blocked@example.com', 42)`},
		{"reply_events", `INSERT INTO reply_events (id, enrollment_id, mailbox_id, thread_id, message_id, contact_email, occurred_at, sync_version) VALUES ('re-1', 'enr-1', 'mbx-1', 't-1', 'msg-1', 'jane@target.com', '2026-03-24T12:00:00Z', 42)`},
		{"learnings", `INSERT INTO learnings (id, type, content, sync_version) VALUES (1, 'tone', 'be more casual', 42)`},
		{"deals", `INSERT INTO deals (id, source, source_id, name, sync_version) VALUES ('d-1', 'hubspot', 'h-1', 'Big Deal', 42)`},
	}

	for _, tc := range tables {
		_, err := d.Exec(tc.insertSQL)
		if err != nil {
			t.Fatalf("table %s: sync_version column missing or insert failed: %v", tc.name, err)
		}

		var sv int
		err = d.QueryRow("SELECT sync_version FROM "+tc.name+" LIMIT 1").Scan(&sv)
		if err != nil {
			t.Fatalf("table %s: reading sync_version failed: %v", tc.name, err)
		}
		if sv != 42 {
			t.Fatalf("table %s: sync_version = %d, want 42", tc.name, sv)
		}
	}
}

func TestUpsertRow(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	engine := NewEngine(d, nil, "")

	// Insert a new row via upsertRow
	err := engine.upsertRow(account.SyncRow{
		Table:   "suppressions",
		ID:      "sup-1",
		Version: 10,
		Data: map[string]any{
			"scope":  "email",
			"value":  "blocked@example.com",
			"reason": "bounced",
			"source": "system",
		},
	})
	if err != nil {
		t.Fatal(err)
	}

	var scope, value, reason string
	var sv int
	err = d.QueryRow(`SELECT scope, value, reason, sync_version FROM suppressions WHERE id = 'sup-1'`).Scan(&scope, &value, &reason, &sv)
	if err != nil {
		t.Fatal(err)
	}
	if scope != "email" || value != "blocked@example.com" || reason != "bounced" || sv != 10 {
		t.Fatalf("unexpected row: scope=%s value=%s reason=%s sv=%d", scope, value, reason, sv)
	}

	// Upsert same row with updated data
	err = engine.upsertRow(account.SyncRow{
		Table:   "suppressions",
		ID:      "sup-1",
		Version: 20,
		Data: map[string]any{
			"scope":  "email",
			"value":  "blocked@example.com",
			"reason": "not interested reply",
			"source": "webhook",
		},
	})
	if err != nil {
		t.Fatal(err)
	}

