func TestSyncStateRoundTrip(t *testing.T) {
	d := setupTestDB(t)
	defer d.Close()

	engine := NewEngine(d, nil, "")

	// Load empty state
	state, err := engine.loadSyncState()
	if err != nil {
		t.Fatal(err)
	}
