import { QueryCtx, MutationCtx } from "./_generated/server";

// Authenticate a user by their nurge token and return their userId.
export async function authenticateUser(
  ctx: QueryCtx | MutationCtx,
  token: string
): Promise<string> {
  const user = await ctx.db
    .query("users")
    .withIndex("by_token", (q) => q.eq("token", token))
    .first();
  if (!user) {
    throw new Error("Invalid auth token");
  }
  return user._id;
}

// Get next sync version for a user and increment it.
export async function nextSyncVersion(
  ctx: MutationCtx,
  userId: string
): Promise<number> {
  const syncState = await ctx.db
    .query("syncState")
    .withIndex("by_user", (q) => q.eq("userId", userId))
    .first();

  const next = (syncState?.lastSyncVersion ?? 0) + 1;

  if (syncState) {
    await ctx.db.patch(syncState._id, { lastSyncVersion: next });
  } else {
    await ctx.db.insert("syncState", { userId, lastSyncVersion: next });
  }

  return next;
}

// Check if a contact is suppressed (by email or domain).
export async function isSuppressed(
  ctx: QueryCtx,
  userId: string,
  email: string
): Promise<{ suppressed: boolean; reason?: string }> {
  // Check email suppression
  const emailSup = await ctx.db
    .query("suppressions")
    .withIndex("by_lookup", (q) =>
      q.eq("userId", userId).eq("scope", "email").eq("value", email)
    )
    .first();
  if (emailSup) {
    return { suppressed: true, reason: emailSup.reason };
  }

  // Check domain suppression
  const domain = email.split("@")[1];
  if (domain) {
    const domainSup = await ctx.db
      .query("suppressions")
      .withIndex("by_lookup", (q) =>
        q.eq("userId", userId).eq("scope", "domain").eq("value", domain)
      )
      .first();
    if (domainSup) {
      return { suppressed: true, reason: domainSup.reason };
    }
  }

  return { suppressed: false };
}

// Count sends for a mailbox on a given day for a specific send type.
export async function countSendsForDay(
  ctx: QueryCtx,
  mailboxId: string,
  sendType: string,
  dayStr: string // YYYY-MM-DD
): Promise<number> {
  const events = await ctx.db
    .query("mailboxSendEvents")
    .withIndex("by_mailbox_day", (q) =>
      q.eq("mailboxId", mailboxId).gte("sentAt", dayStr + "T00:00:00Z").lte("sentAt", dayStr + "T23:59:59Z")
    )
    .collect();

  return events.filter((e) => e.sendType === sendType).length;
}

// Get today's date string in YYYY-MM-DD format for a given timezone.
export function todayInTimezone(timezone: string): string {
  try {
    const now = new Date();
    const formatted = now.toLocaleDateString("en-CA", { timeZone: timezone });
    return formatted; // en-CA gives YYYY-MM-DD format
  } catch {
    // Fallback to UTC
    return new Date().toISOString().split("T")[0];
  }
}

// Check if current time is within the mailbox send window.
export function withinSendWindow(
  startHour: number,
  endHour: number,
  timezone: string
): boolean {
  try {
    const now = new Date();
    const hourStr = now.toLocaleString("en-US", {
      timeZone: timezone,
      hour: "numeric",
      hour12: false,
    });
    const hour = parseInt(hourStr, 10);
    return hour >= startHour && hour < endHour;
  } catch {
    return true; // If timezone is invalid, allow sending
  }
}

