import { v } from "convex/values";
import { action } from "./_generated/server";

// Request a Unipile hosted auth link for connecting Gmail or LinkedIn
export const requestConnectionLink = action({
  args: {
    userId: v.string(),
    provider: v.string(), // GOOGLE | LINKEDIN
  },
  handler: async (ctx, args) => {
    const apiKey = process.env.UNIPILE_API_KEY;
    const apiUrl = process.env.UNIPILE_API_URL;
    const convexSiteUrl = process.env.CONVEX_SITE_URL;

    if (!apiKey || !apiUrl) {
      throw new Error("Unipile API key or URL not configured");
    }

    const notifyUrl = `${convexSiteUrl}/api/unipile-account-callback`;

    const resp = await fetch(`${apiUrl}/api/v1/hosted/request_link`, {
      method: "POST",
      headers: {
        "X-API-KEY": apiKey,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        type: "create",
        providers: [args.provider],
        notify_url: notifyUrl,
        name: args.userId, // Pass user ID for matching on callback
        expiresOn: new Date(Date.now() + 30 * 60 * 1000).toISOString(), // 30 min expiry
      }),
    });

    if (!resp.ok) {
      const error = await resp.text();
      throw new Error(`Unipile request_link failed: ${error}`);
    }

    const result = await resp.json();
    return { url: result.url };
  },
});

// Backfill emails from Unipile (90 days of sent history)
export const backfillEmails = action({
  args: {
    userId: v.string(),
    unipileAccountId: v.string(),
  },
  handler: async (ctx, args) => {
    const apiKey = process.env.UNIPILE_API_KEY;
    const apiUrl = process.env.UNIPILE_API_URL;

    if (!apiKey || !apiUrl) {
      throw new Error("Unipile API key or URL not configured");
    }

    const since = new Date(Date.now() - 90 * 24 * 60 * 60 * 1000).toISOString();
    let cursor: string | undefined;
    let totalFetched = 0;

    do {
      const params = new URLSearchParams({
        account_id: args.unipileAccountId,
        folder: "SENT",
        after: since,
        limit: "100",
      });
      if (cursor) {
        params.set("cursor", cursor);
      }

      const resp = await fetch(`${apiUrl}/api/v1/emails?${params}`, {
        headers: { "X-API-KEY": apiKey },
      });

      if (!resp.ok) {
        const error = await resp.text();
        throw new Error(`Unipile email list failed: ${error}`);
      }

      const result = await resp.json();
      const emails = result.items || result.data || [];

      if (emails.length === 0) break;

      // Store emails in Convex (batch)
      for (const email of emails) {
        const toEmails = (email.to || []).map(
          (t: any) => t.identifier || t.email || ""
        );
        const ccEmails = (email.cc || []).map(
          (c: any) => c.identifier || c.email || ""
        );

        await ctx.runMutation(internal.unipile.storeEmail, {
          userId: args.userId,
          email: {
            externalId: email.id || `uni-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
            source: "unipile",
            direction: "outbound",
            threadId: email.thread_id || "",
            subject: email.subject || "",
            fromEmail: email.from?.identifier || "",
            toEmails: JSON.stringify(toEmails),
            ccEmails: JSON.stringify(ccEmails),
            date: email.date || new Date().toISOString(),
            snippet: email.body_plain?.substring(0, 200) || "",
            unipileId: email.id || "",
            providerId: email.provider_id
              ? JSON.stringify(email.provider_id)
              : "",
            unipileAccountId: args.unipileAccountId,
          },
        });
        totalFetched++;
      }

      cursor = result.cursor || result.next_cursor;
    } while (cursor);

    return { totalFetched };
  },
});

import { internal } from "./_generated/api";
import { internalMutation } from "./_generated/server";

export const storeEmail = internalMutation({
  args: {
    userId: v.string(),
    email: v.object({
      externalId: v.string(),
      source: v.string(),
      direction: v.string(),
      threadId: v.string(),
      subject: v.optional(v.string()),
      fromEmail: v.string(),
      toEmails: v.string(),
      ccEmails: v.optional(v.string()),
      date: v.string(),
      snippet: v.optional(v.string()),
      unipileId: v.optional(v.string()),
      providerId: v.optional(v.string()),
      unipileAccountId: v.optional(v.string()),
    }),
  },
  handler: async (ctx, args) => {
    // Check if email already exists
    const existing = await ctx.db
      .query("emails")
      .withIndex("by_external_id", (q) =>
        q.eq("externalId", args.email.externalId)
      )
      .first();

    const syncState = await ctx.db
      .query("syncState")
      .withIndex("by_user", (q) => q.eq("userId", args.userId))
      .first();
    const version = (syncState?.lastSyncVersion ?? 0) + 1;

    if (existing) {
      await ctx.db.patch(existing._id, {
        ...args.email,
        syncVersion: version,
      });
    } else {
      await ctx.db.insert("emails", {
        ...args.email,
        class: "unclassified",
        syncVersion: version,
